UPDATE products
category_id = #{categoryId}, name = #{name}, description = #{description}, tags = #{tags}, rating = #{rating}, sold = #{sold}, activity_label = #{activityLabel}, original_price = #{originalPrice}, price = #{price}, stock = #{stock}, status = #{status}, update_time = NOW()
